import json

# Create the requested transactions explicitly
income_transactions = [
    ("income", "consulting", 5000, "Client payment from consulting work"),
    ("income", "product_sales", 1500, "Product sale"),
    ("income", "referral_income", 500, "Referral bonus"),
]

expense_transactions = [
    ("expense", "software_subscriptions", 299, "Software subscriptions"),
    ("expense", "marketing_ads", 800, "Marketing ads"),
    ("expense", "professional_development", 450, "Professional development"),
    ("expense", "meals", 125, "Business lunch"),
]

created = {"income": [], "expenses": []}

for ttype, cat, amt, desc in income_transactions:
    resp = json.loads(tools.create_transaction(transaction_type=ttype, category=cat, amount=amt, description=desc))
    created["income"].append(resp)

for ttype, cat, amt, desc in expense_transactions:
    resp = json.loads(tools.create_transaction(transaction_type=ttype, category=cat, amount=amt, description=desc))
    created["expenses"].append(resp)

# Get financial summary (tool output basis for totals)
summary = json.loads(tools.get_financial_summary())

# Get current checking account balance
checking_balance = json.loads(tools.get_account_balance("checking"))

# Ensure state reflects completed operations
state_summary = json.loads(tools.get_state_summary())

def as_float(x):
    try:
        return float(x)
    except Exception:
        return 0.0

# Build totals by category from the financial summary if available; else compute from created
income_by_category = {}
expense_by_category = {}

if isinstance(summary, dict) and "income_by_category" in summary:
    income_by_category = summary.get("income_by_category") or {}
    expense_by_category = summary.get("expenses_by_category") or {}
    net_income = summary.get("net_income")
    if net_income is None:
        net_income = as_float(summary.get("total_income")) - as_float(summary.get("total_expenses"))
else:
    for item in created["income"]:
        cat = item.get("category")
        income_by_category[cat] = as_float(income_by_category.get(cat)) + as_float(item.get("amount"))
    for item in created["expenses"]:
        cat = item.get("category")
        expense_by_category[cat] = as_float(expense_by_category.get(cat)) + as_float(item.get("amount"))
    net_income = sum(as_float(v) for v in income_by_category.values()) - sum(as_float(v) for v in expense_by_category.values())

result = {
    "created_transactions": created,
    "financial_summary": {
        "total_income_by_category": income_by_category,
        "total_expenses_by_category": expense_by_category,
        "net_income": net_income,
        "checking_account_balance": checking_balance
    },
    "state_summary": state_summary
}
